Extracts **hidden paths and endpoints** from a JS file (`/api/v2/users`, `/admin/...`, relative and absolute URLs) with a set of LinkFinder-style regexes, but this is an original pure-stdlib implementation (no dependencies). Frontend bundles often hold undocumented APIs, debug routes and admin panels that are not in the public navigation.

> This is original ARS3NAL code (not vendored LinkFinder, to avoid pulling in an MIT dependency). Reads a file from disk or a url from the argument (via urllib). Then feed the endpoints into httpx/ffuf to check whether they are alive.

```python
#!/usr/bin/env python3
# jsendpoints.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import re, sys, urllib.request, ssl

# regex catches string literals resembling paths/URLs
ENDPOINT = re.compile(r'''
  (?:"|')                       # quote
  (
    (?:https?:)?//[^"'\s]{3,}    # //host/... or http(s)://
    |
    /[A-Za-z0-9_./?&=#%~+-]{2,}  # /relative/path
    |
    [A-Za-z0-9_./-]+?\.(?:php|asp|aspx|jsp|json|js|xml|do|action)\b[^"'\s]*
  )
  (?:"|')
''', re.VERBOSE)

NOISE = re.compile(r'\.(png|jpe?g|gif|svg|css|woff2?|ttf|ico|mp4)(\?|$)', re.I)

def load(src):
    if src.startswith("http"):
        ctx = ssl.create_default_context(); ctx.check_hostname = False; ctx.verify_mode = ssl.CERT_NONE
        req = urllib.request.Request(src, headers={"User-Agent": "ARS3NAL/1.0"})
        return urllib.request.urlopen(req, timeout=20, context=ctx).read().decode("utf-8", "replace")
    with open(src, encoding="utf-8", errors="replace") as f:
        return f.read()

def extract(text):
    out = set()
    for m in ENDPOINT.finditer(text):
        ep = m.group(1).strip()
        if len(ep) < 3 or NOISE.search(ep):
            continue
        out.add(ep)
    return sorted(out)

def main():
    if len(sys.argv) < 2:
        print("usage: jsendpoints.py <file.js|url> [...]"); sys.exit(1)
    for src in sys.argv[1:]:
        try:
            eps = extract(load(src))
        except Exception as e:
            print(f"[err] {src}: {e}", file=sys.stderr); continue
        print(f"\n# {src}  ({len(eps)})")
        for e in eps:
            print(e)

if __name__ == "__main__":
    main()
```

Run:
```bash
python3 jsendpoints.py app.bundle.js
python3 jsendpoints.py "https://target/static/main.js"
```

Scans JS (or any text) for **hardcoded secrets**: GitHub tokens (`ghp_`, `github_pat_`), AWS Access Key (`AKIA...`), Slack tokens (`xox[baprs]-...`), Google API key (`AIza...`), Stripe (`sk_live_`), JWT, private keys (`-----BEGIN ... PRIVATE KEY-----`) and a generic `api_key=...`. An original stdlib implementation. Every match is printed with its rule name and context.

> This is an original set of regexes (not vendored SecretFinder). Additionally/for verification use trufflehog: it checks for itself whether a key is live. trufflehog is licensed under **AGPL-3.0** - it CANNOT be statically bundled into a GPL-3.0 project, so install it as an external binary and run it separately: `trufflehog filesystem ./js --results=verified` (the flag is exactly `--results=verified`; the old `--only-verified` is deprecated).

```python
#!/usr/bin/env python3
# jssecrets.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import re, sys, urllib.request, ssl

RULES = {
    "github-pat-classic": r"ghp_[A-Za-z0-9]{36}",
    "github-pat-fine":    r"github_pat_[A-Za-z0-9_]{60,}",
    "github-oauth":       r"gho_[A-Za-z0-9]{36}",
    "aws-akia":           r"AKIA[0-9A-Z]{16}",
    "aws-asia":           r"ASIA[0-9A-Z]{16}",
    "slack-token":        r"xox[baprs]-[0-9A-Za-z-]{10,48}",
    "slack-webhook":      r"https://hooks\.slack\.com/services/T[0-9A-Za-z_/]+",
    "google-api":         r"AIza[0-9A-Za-z_-]{35}",
    "stripe-live":        r"sk_live_[0-9A-Za-z]{20,}",
    "stripe-pub":         r"pk_live_[0-9A-Za-z]{20,}",
    "jwt":                r"eyJ[A-Za-z0-9_-]{8,}\.eyJ[A-Za-z0-9_-]{8,}\.[A-Za-z0-9_-]{8,}",
    "private-key":        r"-----BEGIN (?:RSA |EC |DSA |OPENSSH )?PRIVATE KEY-----",
    "generic-api-key":    r"(?i)(?:api[_-]?key|secret|token)['\"]?\s*[:=]\s*['\"][A-Za-z0-9_\-]{16,}['\"]",
    "firebase":           r"[a-z0-9-]+\.firebaseio\.com",
}
COMPILED = {k: re.compile(v) for k, v in RULES.items()}

def load(src):
    if src.startswith("http"):
        ctx = ssl.create_default_context(); ctx.check_hostname = False; ctx.verify_mode = ssl.CERT_NONE
        req = urllib.request.Request(src, headers={"User-Agent": "ARS3NAL/1.0"})
        return urllib.request.urlopen(req, timeout=20, context=ctx).read().decode("utf-8", "replace")
    with open(src, encoding="utf-8", errors="replace") as f:
        return f.read()

def scan(text):
    hits = []
    for name, rx in COMPILED.items():
        for m in rx.finditer(text):
            val = m.group(0)
            hits.append((name, val[:80]))
    return hits

def main():
    if len(sys.argv) < 2:
        print("usage: jssecrets.py <file.js|url> [...]"); sys.exit(1)
    total = 0
    for src in sys.argv[1:]:
        try:
            hits = scan(load(src))
        except Exception as e:
            print(f"[err] {src}: {e}", file=sys.stderr); continue
        for name, val in hits:
            total += 1
            print(f"[{name}] {src}\n    {val}")
    print(f"\n[=] {total} potential secrets", file=sys.stderr)

if __name__ == "__main__":
    main()
```

Run:
```bash
python3 jssecrets.py main.js
python3 jssecrets.py "https://target/static/app.js"
```
